from flask import Flask, request, jsonify
import pickle
import os
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
EXPIRATION_TIME = 3600  # 1 hour in seconds

def load_cache():
    if not os.path.exists(CACHE_DIR):
        return {}
    with open(os.path.join(CACHE_DIR, 'cache.pkl'), 'rb') as f:
        cache = pickle.load(f)
    return {key: value for key, (data, timestamp) in cache.items() if time.time() - timestamp < EXPIRATION_TIME}

def save_cache(cache):
    os.makedirs(CACHE_DIR, exist_ok=True)
    with open(os.path.join(CACHE_DIR, 'cache.pkl'), 'wb') as f:
        pickle.dump({key: (data, time.time()) for key, data in cache.items()}, f)

@app.route('/api', methods=['GET'])
def api():
    cache = load_cache()
    url = request.args.get('url')
    if url in cache:
        return jsonify(cache[url][0])
    
    # Simulate expensive API response
    response_data = {
        'data': [1, 2, 3],
        'metadata': {'timestamp': time.time()}
    }
    
    cache[url] = (response_data, time.time())
    save_cache(cache)
    
    return jsonify(response_data)

if __name__ == '__main__':
    app.run(debug=True)